import json
import requests

# Define the services, routes, and upstream targets
services = [
    {
        "name": "service1",
        "url": "http://example.com"
    },
    {
        "name": "service2",
        "url": "http://example.net"
    }
]
routes = [
    {
        "paths": ["/path1"],
        "methods": ["GET"],
        "strip_path": False,
        "preserve_host": True,
        "service": services[0]["name"]
    },
    {
        "paths": ["/path2"],
        "methods": ["POST"],
        "strip_path": False,
        "preserve_host": True,
        "service": services[1]["name"]
    }
]
upstreams = [
    {
        "name": "upstream1",
        "targets": [
            {
                "url": "http://example.com:80"
            },
            {
                "url": "http://example.net:80"
            }
        ]
    }
]

# Configure Kong via Admin API
admin_endpoint = "https://kong:8443/api"
headers = {"Content-Type": "application/json"}

# Create services
for service in services:
    response = requests.post(f"{admin_endpoint}/services", json=service, headers=headers)
    if response.status_code != 201:
        print("Error creating service")
        exit(1)

# Create routes
for route in routes:
    response = requests.post(f"{admin_endpoint}/routes", json=route, headers=headers)
    if response.status_code != 201:
        print("Error creating route")
        exit(1)

# Create upstreams
for upstream in upstreams:
    response = requests.post(f"{admin_endpoint}/upstreams", json=upstream, headers=headers)
    if response.status_code != 201:
        print("Error creating upstream")
        exit(1)

# Configure rate limiting for Kong
rate_limit = {
    "minute": 50,
    "hour": 100,
    "day": 200
}
response = requests.post(f"{admin_endpoint}/plugins", json={
    "name": "rate-limiting",
    "config": rate_limit
}, headers=headers)
if response.status_code != 201:
    print("Error configuring rate limiting")
